+	ReloaderTimingsMS    map[string]int64 `json:"reloader_timings_ms"`
+}
+
+// ReloadStatusManager keeps reload status available to the web handler and on disk.
+type ReloadStatusManager struct {
+	mu     sync.RWMutex
+	path   string
+	status ReloadStatus
+}
+
+// NewReloadStatusManager restores a previous status when it is available. Bad or
+// missing files deliberately leave the manager at its useful zero state.
+func NewReloadStatusManager(dir string) *ReloadStatusManager {
+	m := &ReloadStatusManager{path: filepath.Join(dir, "reload-status.json")}
+	m.status = emptyReloadStatus()
+	b, err := os.ReadFile(m.path)
+	if err != nil {
+		return m
+	}
+	var status ReloadStatus
+	if json.Unmarshal(b, &status) == nil {
+		if status.AppliedReloaders == nil {
+			status.AppliedReloaders = []string{}
+		}
+		if status.ReloaderTimingsMS == nil {
+			status.ReloaderTimingsMS = map[string]int64{}
+		}
+		m.status = status
+	}
+	return m
+}
+
+func emptyReloadStatus() ReloadStatus {
+	return ReloadStatus{ErrorCategory: "none", AppliedReloaders: []string{}, ReloaderTimingsMS: map[string]int64{}}
+}
+
+func (m *ReloadStatusManager) Get() ReloadStatus {
+	m.mu.RLock()
+	defer m.mu.RUnlock()
+	s := m.status
+	s.AppliedReloaders = append([]string(nil), s.AppliedReloaders...)
+	s.ReloaderTimingsMS = make(map[string]int64, len(s.ReloaderTimingsMS))
+	for k, v := range s.ReloaderTimingsMS {
+		s.ReloaderTimingsMS[k] = v
+	}
+	return s
+}
+
+// Record makes the supplied outcome observable before best-effort persistence.
+func (m *ReloadStatusManager) Record(status ReloadStatus) {
+	m.mu.Lock()
+	m.status = status
+	b, err := json.Marshal(status)
+	if err == nil {
+		_ = os.MkdirAll(filepath.Dir(m.path), 0o755)
+		tmp := m.path + ".tmp"
+		if os.WriteFile(tmp, b, 0o644) == nil {
+			_ = os.Rename(tmp, m.path)
+		}
+	}
+	m.mu.Unlock()
+}
